import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { User, LogOut, LayoutDashboard } from 'lucide-react'; // Solo los que usas

const Header = ({ isLoggedIn, userRole, cerrarSesion }) => {
  const navigate = useNavigate();
  const nombreUsuario = localStorage.getItem('user-email')?.split('@')[0] || "Usuario";

  return (
    <header style={headerContainer}>
      <div style={logoSection} onClick={() => navigate('/')}>
        <span style={logoWhite}>OFERTAS</span>
        <span style={logoOrange}>APP</span>
      </div>

      <nav style={navLinks}>
        {!isLoggedIn ? (
          <>
            <Link to="/login" style={linkWhite}><User size={18} /> <span>Crear una cuenta</span></Link>
            <Link to="/login" style={loginButton}>Ingresar</Link>
          </>
        ) : (
          <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
            <span style={{ color: 'white', fontSize: '0.9rem' }}>
              Hola, <strong style={{ color: '#e67e22' }}>{nombreUsuario}</strong>
            </span>

            <button 
              onClick={() => navigate(userRole === 'vendedor' ? '/dashboard' : '/panel-cliente')} 
              style={panelButton}
            >
              <LayoutDashboard size={18} />
              <span>Mi Panel</span>
            </button>
            
            <button onClick={cerrarSesion} style={logoutBtn}>
              <LogOut size={18} />
            </button>
          </div>
        )}
      </nav>
    </header>
  );
};

const headerContainer = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '0 5%', background: '#1e293b', height: '75px', position: 'sticky', top: 0, zIndex: 1000 };
const logoSection = { cursor: 'pointer', fontSize: '1.6rem', fontWeight: '800' };
const logoWhite = { color: '#ffffff' };
const logoOrange = { color: '#e67e22', marginLeft: '5px' };
const navLinks = { display: 'flex', alignItems: 'center', gap: '20px' };
const linkWhite = { color: '#ffffff', textDecoration: 'none', fontSize: '0.95rem', display: 'flex', alignItems: 'center', gap: '8px' };
const loginButton = { background: '#e67e22', color: 'white', padding: '10px 25px', borderRadius: '12px', textDecoration: 'none', fontWeight: 'bold' };
const logoutBtn = { background: 'none', border: 'none', color: '#ff4d4d', cursor: 'pointer' };
const panelButton = { background: 'rgba(230, 126, 34, 0.1)', color: '#e67e22', border: '1px solid #e67e22', padding: '8px 15px', borderRadius: '10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };

export default Header;
